                                        <span className={clsx("inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full text-xs font-semibold", user.isActive ? "bg-green-50 text-green-700 border border-green-200" : "bg-red-50 text-red-700 border border-red-200")}>
                                            <div className={clsx("w-1.5 h-1.5 rounded-full", user.isActive ? "bg-green-500" : "bg-red-500")} />
                                            {user.isActive ? 'Active' : 'Deactivated'}
                                        </span>
                                    </td>
                                    <td className="px-6 py-4 whitespace-nowrap text-sm text-brandText-muted">
                                        {new Date(user.createdAt).toLocaleDateString()}
